{
var src = inputs.Length > 0 ? inputs[0] : null;
    if (src == null)
        return new PixelBuffer(context.TileSize, context.TileSize);

    var type = GetChoice(parameters, "sharpenType", "unsharpMask");
    var strength = GetFloat(parameters, "intensity", 0.5f);
    var radius = GetFloat(parameters, "radius", 1f);
    var threshold = GetFloat(parameters, "threshold", 0.1f);
    var mixRatio = GetFloat(parameters, "mixRatio", 1f);
    var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

    var size = context.TileSize;
    var result = new PixelBuffer(size, size);

    var rad = Math.Max(1, (int)MathF.Ceiling(radius));

    // Create blurred version for unsharp mask
    var blurred = new PixelBuffer(size, size);
    if (type == "unsharpMask")
    {
        BoxBlur(src, blurred, rad, size);
    }

    result.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);

        float outR, outG, outB;

        switch (type)
        {
            case "laplacian":
            {
                // Laplacian edge detection + add back to original
                var sum = 0f;
                var count = 0;
                for (var dy = -1; dy <= 1; dy++)
                {
                    for (var dx = -1; dx <= 1; dx++)
                    {
                        if (dx == 0 && dy == 0) continue;
                        var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y + dy);
                        sum += (pr + pg + pb) / 3f;
                        count++;
                    }
                }
                var center = (r + g + b) / 3f;
                var laplacian = center - sum / count;
                outR = r + laplacian * strength;
                outG = g + laplacian * strength;
                outB = b + laplacian * strength;
                break;
            }
            case "edgeEnhance":
            {
                // Sobel-based edge enhancement
                float gx = 0, gy = 0;
                for (var dy = -1; dy <= 1; dy++)
                {
                    for (var dx = -1; dx <= 1; dx++)
                    {
                        var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y + dy);
                        var lum = 0.299f * pr + 0.587f * pg + 0.114f * pb;
                        var sx = (dx == 0 ? 0f : dx > 0 ? 1f : -1f) * (dy == 0 ? 2f : 1f);
                        var sy = (dy == 0 ? 0f : dy > 0 ? 1f : -1f) * (dx == 0 ? 2f : 1f);
                        gx += lum * sx;
                        gy += lum * sy;
                    }
                }
                var edge = MathF.Sqrt(gx * gx + gy * gy);
                if (edge > threshold)
                {
                    var enhance = (edge - threshold) / (1f - threshold) * strength;
                    outR = r + enhance * r;
                    outG = g + enhance * g;
                    outB = b + enhance * b;
                }
                else
                {
                    outR = r; outG = g; outB = b;
                }
                break;
            }
            default: // unsharpMask
            {
                var (br, bg, bb, _) = blurred.GetPixel(x, y);
                var diffR = r - br;
                var diffG = g - bg;
                var diffB = b - bb;
                var diffLum = 0.299f * MathF.Abs(diffR) + 0.587f * MathF.Abs(diffG) + 0.114f * MathF.Abs(diffB);

                if (diffLum > threshold)
                {
                    var amount = strength * ((diffLum - threshold) / (1f - threshold));
                    outR = r + diffR * amount;
                    outG = g + diffG * amount;
                    outB = b + diffB * amount;
                }
                else
                {
                    outR = r; outG = g; outB = b;
                }
                break;
            }
        }

        // Mix with original
        if (mixRatio < 0.999f)
        {
            outR = r + (outR - r) * mixRatio;
            outG = g + (outG - g) * mixRatio;
            outB = b + (outB - b) * mixRatio;
        }

        result.SetPixel(x, y,
            Math.Clamp(outR, 0f, 1f),
            Math.Clamp(outG, 0f, 1f),
            Math.Clamp(outB, 0f, 1f),
            preserveAlpha ? a : 1f);
    });

    return result;

private static void BoxBlur(PixelBuffer src, PixelBuffer dst, int radius, int size)
{
    var temp = new PixelBuffer(size, size);
    temp.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var count = 0;
        for (var dx = -radius; dx <= radius; dx++)
        {
            var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y);
            sumR += pr; sumG += pg; sumB += pb; count++;
        }
        var inv = 1f / count;
        temp.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, 1f);
    });
    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var count = 0;
        for (var dy = -radius; dy <= radius; dy++)
        {
            var (pr, pg, pb, _) = temp.GetPixelWrapped(x, y + dy);
            sumR += pr; sumG += pg; sumB += pb; count++;
        }
        var inv = 1f / count;
        dst.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, 1f);
    });
    }
}
